use std::io::{self, Read};
fn is_self_crossing(x: &[i32]) -> bool { for i in 3..x.len() { if x[i] >= x[i-2] && x[i-1] <= x[i-3] { return true; } if i >= 4 && x[i-1] == x[i-3] && x[i] + x[i-4] >= x[i-2] { return true; } if i >= 5 && x[i-2] >= x[i-4] && x[i] + x[i-4] >= x[i-2] && x[i-1] <= x[i-3] && x[i-1] + x[i-5] >= x[i-3] { return true; } } false }
fn main(){ let mut s=String::new(); io::stdin().read_to_string(&mut s).unwrap(); let data:Vec<i32>=s.split_whitespace().map(|x|x.parse().unwrap()).collect(); if data.is_empty(){return}; let mut idx=0; let t=data[idx] as usize; idx+=1; let mut out=Vec::new(); for _ in 0..t{ let n=data[idx] as usize; idx+=1; let x=data[idx..idx+n].to_vec(); idx+=n; out.push(if is_self_crossing(&x){"true"}else{"false"}.to_string()); } print!("{}", out.join("\n\n")); }
